previewCss:
.darma-loader-darma-custom-624 {color: var(--loader-color, #0891b2);
  --loader-secondary-color: #22d3ee;
  --loader-bg: #ffffff;
   width: 40px;
   aspect-ratio: 1;
   outline: 2px solid currentColor;
   background: radial-gradient(farthest-side,currentColor 90%,#0000) 0 0/8px 8px no-repeat, conic-gradient(from 90deg at 10px 10px,#0000 90deg,currentColor 0), conic-gradient(from -90deg at 30px 30px,#0000 90deg,currentColor 0);
   animation: darma-loader-darma-custom-624-l1 1.5s infinite;
}
@keyframes darma-loader-darma-custom-624-l1  {
  0% {background-position:0 0}
25% {background-position:100% 0}
50% {background-position:100% 100%}
75% {background-position:0 100%}
100% {background-position:0 0}
}

